local cjson = require "cjson"
local cookie_name = "session_data"

local function get_cookie(name)
    local cookies = ngx.var.http_cookie
    if not cookies then
        return nil
    end
    
    local pattern = name .. "=([^;]+)"
    local value = cookies:match(pattern)
    
    if value then
        return ngx.unescape_uri(value)
    end
    return nil
end

local function deserialize_session()
    local serialized = get_cookie(cookie_name)
    
    if not serialized then
        return nil
    end
    
    local success, session_data = pcall(cjson.decode, serialized)
    
    if not success then
        ngx.log(ngx.ERR, "Failed to deserialize session: ", session_data)
        return nil
    end
    
    return session_data
end

local function serialize_session(data)
    local success, serialized = pcall(cjson.encode, data)
    
    if not success then
        ngx.log(ngx.ERR, "Failed to serialize session: ", serialized)
        return nil
    end
    
    return serialized
end

local function set_session_cookie(data)
    local serialized = serialize_session(data)
    if not serialized then
        return false
    end
    
    local escaped = ngx.escape_uri(serialized)
    ngx.header["Set-Cookie"] = cookie_name .. "=" .. escaped .. "; Path=/; HttpOnly; Secure; SameSite=Strict"
    return true
end

local session = deserialize_session()

if session then
    ngx.say("User ID: ", session.user_id or "N/A")
    ngx.say("Role: ", session.role or "N/A")
else
    local new_session = {user_id = 1, role = "admin"}
    set_session_cookie(new_session)
    ngx.say("New session created")
